import React, { createContext, useState, useCallback, useEffect } from 'react';
import apiClient from '../api/apiClient';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [token, setToken] = useState(() => localStorage.getItem('authToken') || null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const register = useCallback(async (name, surname, username, password) => {
    setLoading(true);
    setError(null);
    try {
      await apiClient.post('/v1/auth/register', {
        name,
        surname,
        username,
        password,
      });

      const response = await login(username, password);
      return response;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [login]);

  const login = useCallback(async (username, password) => {
    setLoading(true);
    setError(null);
    try {
      const response = await apiClient.post(
        '/v1/auth/login',
        { username, password },
        true // isFormUrlencoded
      );

      const newToken = response.access_token || response.token;
      setToken(newToken);
      apiClient.setToken(newToken);

      // Fetch user profile
      const userResponse = await apiClient.get('/v1/user/me');
      setUser(userResponse);

      return response;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, []);

  const getCurrentUser = useCallback(async () => {
    if (!token) return null;

    setLoading(true);
    try {
      const userResponse = await apiClient.get('/v1/user/me');
      setUser(userResponse);
      return userResponse;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [token]);

  const logout = useCallback(() => {
    setToken(null);
    setUser(null);
    setError(null);
    apiClient.setToken(null);
  }, []);

  // Initialize user on mount or when token changes if needed
  useEffect(() => {
    if (token && !user) {
      getCurrentUser();
    }
  }, [token, user, getCurrentUser]);

  const value = {
    token,
    user,
    loading,
    error,
    register,
    login,
    logout,
    getCurrentUser,
    isAuthenticated: !!token,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
